// USART2 Interrupt Service Routine
// This function handles USART2 global interrupt.
// It is automatically called by the hardware (or Keil simulator)
// when a character is received on PA3 (UART2_RX)
void USART2_IRQHandler(void) {
		// Check if RXNE (Read Data Register Not Empty) interrupt flag is set
    // RXNE flag means a new byte is sitting in DR waiting to be read
    if (USART2->SR & (1U<<5)) {
        uint8_t byte = USART2->DR;   // reading DR also clears the RXNE flag

        // Push into the queue, non-blocking so ISR returns immediately
        // Return value is ignored here because we have no good recovery in ISR context
        // If the queue fills up the byte is dropped, which is the correct behavior
        // (better to lose one character than to stall the ISR and miss subsequent interrupts)
        osQueueSend(&uart_rx_queue, byte);
    }
}

