// Runs in timer service task context, so mutexes and printf are safe
// If this were called from ISR directly we could not use print_mutex here
void motor_timer_callback(void) {
    osMutexAcquire(&print_mutex);
    motor_run();
    osMutexRelease(&print_mutex);
}

// CPU usage reporter callback
// Sums all run ticks, converts each task's share to a percentage, prints a table
// Then resets all counters so the next report reflects only the next 5 second window
// Runs in timer service task context, safe to use mutex and printf
void cpu_report_callback(void) {
    uint32_t count = osGetTaskCount();
    uint32_t total = 0;

    // Sum all task ticks to get the denominator for percentage math
    // Total ticks should be close to 500 (5 seconds * 100Hz) but slight drift is normal
    for (uint32_t i = 0; i < count; i++) {
        total += osGetTaskRunTicks(i);
    }

    // Guard against the impossible-but-possible case of total being 0
    // This could happen right after reset before any tick has accumulated
    if (total == 0) {
        return;
    }

    osMutexAcquire(&print_mutex);

    printf("\n==== CPU USAGE ====\n\r");
    for (uint32_t i = 0; i < count; i++) {
        // Integer percentage math: multiply before divide to preserve precision
        // Otherwise tasks under 1% would show as 0
        uint32_t ticks = osGetTaskRunTicks(i);
        uint32_t pct = (ticks * 100) / total;

        // Index 0 is always the idle task by kernel convention
        // Labeling it explicitly helps read the report at a glance
        if (i == 0) {
					printf("Idle         : %u%% (%u ticks)\n\r", pct, ticks);
				} else {
					printf("Task %u       : %u%% (%u ticks)\n\r", i, pct, ticks);
				}
    }
    printf("Total ticks  : %u\n\r", total);
    printf("===================\n\r");

    osMutexRelease(&print_mutex);

    // Fresh window for the next report, otherwise percentages become lifetime averages
    // and gradually lose sensitivity to current system behavior
    osResetAllRunTicks();
}


void task1(void) {
	while (1) {
		Task1_Profiler++;
		osSemaphoreWait(&semaphore1);
		osMutexAcquire(&print_mutex);
		valve_open();
		osMutexRelease(&print_mutex);
		osSemaphoreSet(&semaphore2);
		osDelay(10);
		}
}


void task2(void) {
	while (1) {
		Task2_Profiler++;
		osSemaphoreWait(&semaphore2);
		osMutexAcquire(&print_mutex);
		valve_close();
		osMutexRelease(&print_mutex);
		osSemaphoreSet(&semaphore1);
		osDelay(10);
		}
}

//periodic scheduler
void task3(void) {
	Periodic_Task1_Profiler++;
}

// UART Listener (Event-Driven Task)
// This task sleeps and waits for UART data
// It consumes 0 CPU cycles until the ISR gives the semaphore
void task4(void) {
    uint8_t rx_byte;

    while (1) {
        // Block until the ISR puts something into the queue
        // Zero CPU cost while waiting, task is in sleeping state
        osQueueReceive(&uart_rx_queue, &rx_byte);

				 osMutexAcquire(&print_mutex);
			
        // Process the command we just received
        if (rx_byte == 'O') {
            printf("Receive\n");
            valve_open();
        }
        else if (rx_byte == 'C') {
            printf("Receive\n");
            valve_close();
        }
				osMutexRelease(&print_mutex);
        // Unknown bytes are silently ignored, could add logging later if needed
    }
	}
	

