void uart_test_task(void) {
    while (1) {
        // Inject 5 characters back-to-back (simulates a UART burst at high baud rate)
        // This is where the queue proves its worth: old single-slot latest_rx_data
        // would lose 4 out of 5 characters, queue catches all of them
        osQueueSend(&uart_rx_queue, 'O');
        osQueueSend(&uart_rx_queue, 'C');
        osQueueSend(&uart_rx_queue, 'O');
        osQueueSend(&uart_rx_queue, 'C');
        osQueueSend(&uart_rx_queue, 'O');

        osDelay(200);  // 2 second gap between bursts
    }
}

int main() {
	// To prevent nested interrupts
	__disable_irq();
	
	// Initialize UART (TX and RX Interrupts)
	uart_tx_init();
	// uart_rx_interrupt_init(); // disabled to isolate queue test from simulator noise

	// Initialize hardware timer
	tim2_1hz_interrupt_init();

	// Initialize semaphores
	osSemaphoreInit(&semaphore1, 1);
	osSemaphoreInit(&semaphore2, 0);
	
	// Initialize the UART RX queue with its backing buffer
	osQueueInit(&uart_rx_queue, uart_rx_buffer, UART_RX_QUEUE_SIZE);
	
	// Initialize mutex
	osMutexInit(&print_mutex);
	
	// Arm the motor timer: period 10 ticks = 100ms (TIM2 runs at 100Hz)
	// Periodic flag = 1 means auto-reload after each expiration
	osTimerCreate(&motor_timer, 10, 1, motor_timer_callback);
	osTimerStart(&motor_timer);
	
	// CPU usage report every 5 seconds (500 ticks * 10ms)
	// Uses the same timer service infrastructure as motor_timer, no extra task needed
	osTimerCreate(&cpu_report_timer, 500, 1, cpu_report_callback);
	osTimerStart(&cpu_report_timer);

	//Initialize kernel
	osKernelInit(SCHED_PRIORITY);

	//Add thread
	// osKernelAddThreads(&task0, &task1, &task2, &task4);

	// Add threads dynamically to the kernel
	// We can check the return values for debugging if we want
  // osKernelAddThread(&task0, 0);
	
	// Timer service gets highest priority so callbacks have low latency
	// It blocks when idle so this does not starve other tasks
	osKernelAddThread(&osTimerServiceTask, 0);
	
  osKernelAddThread(&task1, 1);
	osKernelAddThread(&task2, 2);

	// Task 4 (UART Listener)
	osKernelAddThread(&task4, 3);
	
	// To tes queue
	osKernelAddThread(&uart_test_task, 4);
	
	// DEBUG ONLY: stack overflow detector test task
	// Should trigger osStackOverflowHandler within the first few ticks
	// Comment out this line to disable the test and return to normal operation
	// osKernelAddThread(&overflow_test_task, 4);

	// Set round robin time quanta
	osKernelLaunch(QUANTA);

	while (1) {
	// CPU should never reach here if OS is running
	}
}

void TIM2_IRQHandler(void) {
    // Clear update interrupt flag to acknowledge the interrupt
    TIM2->SR &= ~SR_UIF;

    // Decrement all sleeping tasks' counters
    // We use TIM2 instead of SysTick because osThreadYield() resets SysTick->VAL
    // which also clears COUNTFLAG, making SysTick-based timing unreliable
    osTickDecrement();
	
	
    // Advance software timers, expired ones get pushed to the service task
    // This single line is the hook that drives the entire timer subsystem
    osTimerTick();
	
		// CPU usage accounting: credit this tick to whichever task is currently running
    // currentPt is set by osKernelLaunch and always points to a valid task from then on
    // If we are in the idle task, idle gets the tick - which is exactly what we want
    osAccountCurrentTick();

    // Profiler for debugging the periodic ISR
    Periodic_Task2_Profiler++;
}

